1	import * as Net from "node:net";
2	
3	import { Data, Effect, Layer, ServiceMap } from "effect";
4	
5	export class NetError extends Data.TaggedError("NetError")<{
6	  readonly message: string;
7	  readonly cause?: unknown;
8	}> {}
9	
10	function isErrnoExceptionWithCode(cause: unknown): cause is {
11	  readonly code: string;
12	} {
13	  return (
14	    typeof cause === "object" &&
15	    cause !== null &&
16	    "code" in cause &&
17	    typeof (cause as { readonly code: unknown }).code === "string"
18	  );
19	}
20	
21	const closeServer = (server: Net.Server) => {
22	  try {
23	    server.close();
24	  } catch {
25	    // Ignore close failures during cleanup.
26	  }
27	};
28	
29	const tryReservePort = (port: number): Effect.Effect<number, NetError> =>
30	  Effect.callback<number, NetError>((resume) => {
31	    const server = Net.createServer();
32	    let settled = false;
33	
34	    const settle = (effect: Effect.Effect<number, NetError>) => {
35	      if (settled) return;
36	      settled = true;
37	      resume(effect);
38	    };
39	
40	    server.unref();
41	
42	    server.once("error", (cause) => {
43	      settle(Effect.fail(new NetError({ message: "Could not find an available port.", cause })));
44	    });
45	
46	    server.listen(port, () => {
47	      const address = server.address();
48	      const resolved = typeof address === "object" && address !== null ? address.port : 0;
49	      server.close(() => {
50	        if (resolved > 0) {
51	          settle(Effect.succeed(resolved));
52	          return;
53	        }
54	        settle(Effect.fail(new NetError({ message: "Could not find an available port." })));
55	      });
56	    });
57	
58	    return Effect.sync(() => {
59	      closeServer(server);
60	    });
61	  });
62	
63	export interface NetServiceShape {
64	  /**
65	   * Returns true when a TCP server can bind to {host, port}.
66	   */
67	  readonly canListenOnHost: (port: number, host: string) => Effect.Effect<boolean>;
68	
69	  /**
70	   * Checks loopback availability on both IPv4 and IPv6 localhost addresses.
71	   */
72	  readonly isPortAvailableOnLoopback: (port: number) => Effect.Effect<boolean>;
73	
74	  /**
75	   * Reserve an ephemeral loopback port and release it immediately.
76	   */
77	  readonly reserveLoopbackPort: (host?: string) => Effect.Effect<number, NetError>;
78	
79	  /**
80	   * Resolve an available listening port, preferring the provided port first.
81	   */
82	  readonly findAvailablePort: (preferred: number) => Effect.Effect<number, NetError>;
83	}
84	
85	/**
86	 * NetService - Service tag for startup networking helpers.
87	 */
88	export class NetService extends ServiceMap.Service<NetService, NetServiceShape>()(
89	  "@t3tools/shared/Net/NetService",
90	) {
91	  static readonly layer = Layer.sync(NetService, () => {
92	    /**
93	     * Returns true when a TCP server can bind to {host, port}.
94	     * `EADDRNOTAVAIL` is treated as available so IPv6-absent hosts don't fail
95	     * loopback availability checks.
96	     */
97	    const canListenOnHost = (port: number, host: string): Effect.Effect<boolean> =>
98	      Effect.callback<boolean>((resume) => {
99	        const server = Net.createServer();
100	        let settled = false;
101	
102	        const settle = (value: boolean) => {
103	          if (settled) return;
104	          settled = true;
105	          resume(Effect.succeed(value));
106	        };
107	
108	        server.unref();
109	
110	        server.once("error", (cause) => {
111	          if (isErrnoExceptionWithCode(cause) && cause.code === "EADDRNOTAVAIL") {
112	            settle(true);
113	            return;
114	          }
115	          settle(false);
116	        });
117	
118	        server.once("listening", () => {
119	          server.close(() => {
120	            settle(true);
121	          });
122	        });
123	
124	        server.listen({ host, port });
125	
126	        return Effect.sync(() => {
127	          closeServer(server);
128	        });
129	      });
130	
131	    /**
132	     * Reserve an ephemeral loopback port and release it immediately.
133	     * Returns the reserved port number.
134	     */
135	    const reserveLoopbackPort = (host = "127.0.0.1"): Effect.Effect<number, NetError> =>
136	      Effect.callback<number, NetError>((resume) => {
137	        const probe = Net.createServer();
138	        let settled = false;
139	
140	        const settle = (effect: Effect.Effect<number, NetError>) => {
141	          if (settled) return;
142	          settled = true;
143	          resume(effect);
144	        };
145	
146	        probe.once("error", (cause) => {
147	          settle(Effect.fail(new NetError({ message: "Failed to reserve loopback port", cause })));
148	        });
149	
150	        probe.listen(0, host, () => {
151	          const address = probe.address();
152	          const port = typeof address === "object" && address !== null ? address.port : 0;
153	          probe.close(() => {
154	            if (port > 0) {
155	              settle(Effect.succeed(port));
156	              return;
157	            }
158	            settle(Effect.fail(new NetError({ message: "Failed to reserve loopback port" })));
159	          });
160	        });
161	
162	        return Effect.sync(() => {
163	          closeServer(probe);
164	        });
165	      });
166	
167	    return {
168	      canListenOnHost,
169	      isPortAvailableOnLoopback: (port) =>
170	        Effect.zipWith(
171	          canListenOnHost(port, "127.0.0.1"),
172	          canListenOnHost(port, "::1"),
173	          (ipv4, ipv6) => ipv4 && ipv6,
174	        ),
175	      reserveLoopbackPort,
176	      findAvailablePort: (preferred) =>
177	        Effect.catch(tryReservePort(preferred), () => tryReservePort(0)),
178	    } satisfies NetServiceShape;
179	  });
180	}
