13	describe("normalizeModelSlug", () => {
14	  it("maps known aliases to canonical slugs", () => {
15	    expect(normalizeModelSlug("5.3")).toBe("gpt-5.3-codex");
16	    expect(normalizeModelSlug("gpt-5.3")).toBe("gpt-5.3-codex");
17	  });
18	
19	  it("returns null for empty or missing values", () => {
20	    expect(normalizeModelSlug("")).toBeNull();
21	    expect(normalizeModelSlug("   ")).toBeNull();
22	    expect(normalizeModelSlug(null)).toBeNull();
23	    expect(normalizeModelSlug(undefined)).toBeNull();
24	  });
25	
26	  it("preserves non-aliased model slugs", () => {
27	    expect(normalizeModelSlug("gpt-5.2")).toBe("gpt-5.2");
28	    expect(normalizeModelSlug("gpt-5.2-codex")).toBe("gpt-5.2-codex");
29	  });
30	
31	  it("does not leak prototype properties as aliases", () => {
32	    expect(normalizeModelSlug("toString")).toBe("toString");
33	    expect(normalizeModelSlug("constructor")).toBe("constructor");
34	  });
35	});
36	
37	describe("resolveModelSlug", () => {
38	  it("returns default only when the model is missing", () => {
39	    expect(resolveModelSlug(undefined)).toBe(DEFAULT_MODEL_BY_PROVIDER.codex);
