102	function mapProjectsFromReadModel(
103	  incoming: OrchestrationReadModel["projects"],
104	  previous: Project[],
105	): Project[] {
106	  return incoming.map((project) => {
107	    const existing =
108	      previous.find((entry) => entry.id === project.id) ??
109	      previous.find((entry) => entry.cwd === project.workspaceRoot);
110	    return {
111	      id: project.id,
112	      name: project.title,
113	      cwd: project.workspaceRoot,
114	      model:
115	        existing?.model ??
116	        resolveModelSlug(project.defaultModel ?? DEFAULT_MODEL_BY_PROVIDER.codex),
117	      expanded:
118	        existing?.expanded ??
119	        (persistedExpandedProjectCwds.size > 0
120	          ? persistedExpandedProjectCwds.has(project.workspaceRoot)
121	          : true),
