import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

type ThemeSnapshot = {
  theme: Theme;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

/**
 * Migrate legacy stored values ("light" | "dark" | "system") to new theme ids.
 */
function migrateStoredValue(raw: string | null): string {
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") {
    const prefersDark = window.matchMedia(MEDIA_QUERY).matches;
    return prefersDark ? "t3-dark" : "t3-light";
  }
  return raw ?? DEFAULT_THEME_ID;
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  const id = migrateStoredValue(raw);
  // Persist the migrated value so we only migrate once
  if (raw !== id) {
    localStorage.setItem(STORAGE_KEY, id);
  }
  return id;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  document.documentElement.classList.toggle("dark", theme.isDark);

  const root = document.documentElement.style;
  root.setProperty("--theme-background", theme.colors.background);
  root.setProperty("--theme-foreground", theme.colors.foreground);
  root.setProperty("--theme-accent", theme.colors.accent);
  root.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.setProperty("--theme-editor", theme.colors.editor);
  root.setProperty("--theme-terminal", theme.colors.terminal);
  root.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.setProperty("--theme-font-family", theme.fontFamily);
  root.setProperty("--theme-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(resolveTheme(getStoredThemeId()));

function getSnapshot(): ThemeSnapshot {
  const theme = resolveTheme(getStoredThemeId());

  if (lastSnapshot && lastSnapshot.theme.id === theme.id) {
    return lastSnapshot;
  }

  lastSnapshot = { theme };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveTheme(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;

  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}

