import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({
  theme,
  selected,
  onSelect,
}: {
  theme: Theme;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-start gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onSelect}
    >
      {/* Preview swatch showing sidebar / editor / status bar layout */}
      <div
        className="mt-0.5 flex h-8 w-12 shrink-0 overflow-hidden rounded-md border border-border"
        aria-hidden="true"
      >
        <div className="w-1/3" style={{ backgroundColor: theme.colors.sidebar }} />
        <div className="flex w-2/3 flex-col">
          <div className="flex-1" style={{ backgroundColor: theme.colors.editor }} />
          <div className="h-1.5" style={{ backgroundColor: theme.colors.statusBar }} />
        </div>
      </div>

      <span className="flex flex-1 flex-col">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="text-xs">{theme.isDark ? "Dark theme" : "Light theme"}</span>
      </span>

      {/* Accent color dot */}
      <span
        className="mt-1.5 size-3 shrink-0 rounded-full border border-border"
        style={{ backgroundColor: theme.colors.accent }}
        aria-hidden="true"
      />

      {selected ? (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme selection">
      {availableThemes.map((t) => (
        <ThemeSwatch
          key={t.id}
          theme={t}
          selected={theme.id === t.id}
          onSelect={() => setTheme(t.id)}
        />
      ))}
    </div>
  );
}

